from vex_sdk import Vex
from pydantic_ai import Agent
from pydantic import BaseModel

vex = Vex(api_key="vex_12345")

class EscalationPolicy(BaseModel):
    keywords: list = ["billing_dispute", "outage", "refund"]
    auto_escalate: bool

@vex.result_validator(
    check="policy_compliance",
    rules=[
        "escalation_keywords_present",
        "tone_professional",
        "no_apologies_for_policy"
    ]
)
async def validate_escalation(response: BaseModel) -> dict:
    """Verify escalation logic and policy compliance"""
    verification = await vex.verify({
        'text': response.summary,
        'policy': 'support_escalation',
        'threshold': 0.9
    })

    if verification.escalation_score > 0.8:
        response.needs_escalation = True

    return {
        'passed': verification.passed,
        'escalation_triggered': response.needs_escalation,
        'risk_score': verification.risk_score
    }
